import java.lang.reflect.*;
public class MethodReflect {
    static class Calc {
        int add(int a, int b) { return a + b; }
        static int square(int x) { return x * x; }
    }
    public static void main(String[] args) throws Exception {
        Calc c = new Calc();
        Method add = Calc.class.getDeclaredMethod("add", int.class, int.class);
        System.out.println(add.invoke(c, 3, 4));
        Method sq = Calc.class.getDeclaredMethod("square", int.class);
        System.out.println(sq.invoke(null, 5));
        System.out.println(add.getParameterCount());
    }
}
